#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int main() {
    int n;
    scanf("%d", &n);
    char num[n+1];
    scanf("%s", num);
    char lis[n+1];
    int count = 0;
    int lis_index = 0;

    for (int i = 0; i < n; i++) {
        if (num[i] == '1') {
            count++;
        } else {
            lis[lis_index++] = count + '0';
            count = 0;
        }
    }

    if (num[n-1] == '1') {
        lis[lis_index++] = count + '0';
    } else {
        lis[lis_index++] = '0';
    }

    lis[lis_index] = '\0';
    printf("%s", lis);
    return 0;
}
